/**
 * Day 7 Phase 4: Fundamental + Event Setup Diagnosis
 * Understand why 0 fundamental and 0 event proposals are ever generated
 */

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

function parseJson(str: string | null) {
  if (!str) return null;
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

async function main() {
  console.log('\n========== DAY 7 PHASE 4: FUNDAMENTAL + EVENT DIAGNOSIS ==========\n');

  try {
    // Check all proposals ever generated by setup type
    console.log('[1] Proposal Generation by Setup Type (All Time):\n');
    
    const proposalsByType = await prisma.strategyProposal.groupBy({
      by: ['setupType'],
      _count: true
    });

    console.table(proposalsByType.map(p => ({
      setupType: p.setupType,
      count: p._count
    })));

    // Check latest proposals
    console.log('\n[2] Latest Proposals (Last 20):\n');
    
    const latestProposals = await prisma.strategyProposal.findMany({
      orderBy: { createdAt: 'desc' },
      take: 20
    });

    const proposalTable = latestProposals.map(p => ({
      id: p.id,
      setup: p.setupType,
      symbol: p.symbol,
      createdAt: new Date(p.createdAt).toLocaleString()
    }));
    console.table(proposalTable);

    // Count by setup in recent window
    const recentProposals = await prisma.strategyProposal.findMany({
      where: {
        createdAt: { gte: new Date(new Date().getTime() - 7 * 24 * 60 * 60 * 1000) } // Last 7 days
      }
    });

    console.log('\n[3] Proposals in Last 7 Days:\n');
    const setup_trend = recentProposals.filter(p => p.setupType === 'trend').length;
    const setup_rebound = recentProposals.filter(p => p.setupType === 'rebound').length;
    const setup_fundamental = recentProposals.filter(p => p.setupType === 'fundamental').length;
    const setup_event = recentProposals.filter(p => p.setupType === 'event').length;

    console.log(`  Trend: ${setup_trend}`);
    console.log(`  Rebound: ${setup_rebound}`);
    console.log(`  Fundamental: ${setup_fundamental}`);
    console.log(`  Event: ${setup_event}`);
    console.log(`  Total: ${recentProposals.length}\n`);

    // Check research snapshot for fundamental candidate evaluation
    console.log('[4] Latest Autonomous Research Snapshot:\n');
    
    const latestSnapshot = await prisma.autonomousResearchSnapshot.findFirst({
      orderBy: { createdAt: 'desc' }
    });

    if (latestSnapshot) {
      console.log(`  ID: #${latestSnapshot.id}`);
      console.log(`  Created: ${latestSnapshot.createdAt}`);
      console.log(`  Snapshot Date: ${latestSnapshot.snapshotDate}`);
      
      // Try to parse candidate stocks
      if (latestSnapshot.candidateStocks) {
        const candidates = parseJson(latestSnapshot.candidateStocks);
        if (candidates && Array.isArray(candidates)) {
          console.log(`\n  Candidates evaluated: ${candidates.length}`);
          
          console.log(`  Candidate Setup Type Distribution:`);
          const setupDist = candidates.reduce((acc: any, c: any) => {
            const setup = c.recommendedSetupType || 'unknown';
            acc[setup] = (acc[setup] || 0) + 1;
            return acc;
          }, {});
          
          for (const [setup, count] of Object.entries(setupDist)) {
            console.log(`    ${setup}: ${count}`);
          }

          // Check fundamental-related candidates
          const fundamentalCandidates = candidates.filter((c: any) => 
            c.recommendedSetupType === 'fundamental' || c.reason?.includes('fundamental')
          );
          console.log(`\n  Fundamental-labeled candidates: ${fundamentalCandidates.length}`);
          
          if (fundamentalCandidates.length > 0) {
            console.log(`  Why fundamental setup selected:`);
            for (const fc of fundamentalCandidates.slice(0, 3)) {
              console.log(`    - ${fc.symbol}: ${fc.reason?.substring(0, 80)}`);
            }
          }

          // Check event-related candidates
          const eventCandidates = candidates.filter((c: any) => 
            c.recommendedSetupType === 'event' || c.reason?.includes('event')
          );
          console.log(`\n  Event-labeled candidates: ${eventCandidates.length}`);
          
          if (eventCandidates.length > 0) {
            console.log(`  Why event setup selected:`);
            for (const ec of eventCandidates.slice(0, 3)) {
              console.log(`    - ${ec.symbol}: ${ec.reason?.substring(0, 80)}`);
            }
          }
        }
      }
    } else {
      console.log('  No autonomous research snapshot found');
    }

    // Check DecisionLayerEngine decision logs if available
    console.log('\n[5] Decision Layer Analysis:\n');
    
    const recentTrades = await prisma.simulatedTrade.findMany({
      orderBy: { createdAt: 'desc' },
      take: 50
    });

    const setupCounts = {
      trend: recentTrades.filter(t => t.setupType === 'trend').length,
      rebound: recentTrades.filter(t => t.setupType === 'rebound').length,
      fundamental: recentTrades.filter(t => t.setupType === 'fundamental').length,
      event: recentTrades.filter(t => t.setupType === 'event').length
    };

    console.log(`  In last 50 SimulatedTrade records:`);
    console.log(`    Trend: ${setupCounts.trend}`);
    console.log(`    Rebound: ${setupCounts.rebound}`);
    console.log(`    Fundamental: ${setupCounts.fundamental}`);
    console.log(`    Event: ${setupCounts.event}\n`);

    // Diagnosis
    console.log('[6] Diagnosis:\n');
    
    if (setup_fundamental === 0) {
      console.log('  ❌ Fundamental proposals: BLOCKED');
      console.log('  Possible reasons:');
      console.log('    - DecisionLayerEngine not assigning "fundamental" setupType');
      console.log('    - FundamentalResearchService returning insufficient data');
      console.log('    - No candidates meeting fundamental criteria (revenue growth + margin quality)');
      console.log('    - Confidence too low for fundamental proposals');
    } else {
      console.log(`  ✅ Fundamental proposals: WORKING (${setup_fundamental} generated)`);
    }

    if (setup_event === 0) {
      console.log('\n  ❌ Event proposals: BLOCKED');
      console.log('  Possible reasons:');
      console.log('    - EventSummaryEngine not returning LIVE_CONFIDENT/MIXED_SOURCE');
      console.log('    - EventSourceQualityEngine still returning INSUFFICIENT_EVENT_DATA');
      console.log('    - No candidates with sufficient event momentum');
      console.log('    - RSS sync incomplete despite Day 3 efforts');
    } else {
      console.log(`\n  ✅ Event proposals: WORKING (${setup_event} generated)`);
    }

    console.log('\n  Setup Diversity Status:');
    console.log(`    Trend: ${'✅ Active' } (${setupCounts.trend} recent)`);
    console.log(`    Rebound: ${'✅ Active'} (${setupCounts.rebound} recent)`);
    console.log(`    Fundamental: ${setupCounts.fundamental > 0 ? '✅ Active' : '❌ Blocked'} (${setupCounts.fundamental} recent)`);
    console.log(`    Event: ${setupCounts.event > 0 ? '✅ Active' : '❌ Blocked'} (${setupCounts.event} recent)`);

    console.log('\n========== END PHASE 4 ==========\n');
  } catch (error) {
    console.error('Error in Phase 4:', error);
    process.exit(1);
  } finally {
    await prisma.$disconnect();
  }
}

main();
